/**
 * @summary List all career applications
 */
export const getListCareersUrl = (params?: ListCareersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/careers?${stringifiedParams}`
    : `/api/careers`;
};

export const listCareers = async (
  params?: ListCareersParams,
  options?: RequestInit,
): Promise<CareerListResponse> => {
  return customFetch<CareerListResponse>(getListCareersUrl(params), {
    ...options,
    method: "GET",
  });
};

